import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { Users, Mail, Phone, MapPin, Award, BookOpen, Calendar, Linkedin, Twitter, Github, GraduationCap, Shield, Star, Clock, Building, User, X, UserCheck, Briefcase, Settings } from 'lucide-react';

// Import Swiper React components
import { Swiper, SwiperSlide } from 'swiper/react';

// Import Swiper styles
import 'swiper/css';
import 'swiper/css/parallax';
import 'swiper/css/pagination';
import 'swiper/css/navigation';

// Import required modules - Updated for Swiper v9
import { Parallax, Pagination, Navigation, Autoplay } from 'swiper';

// Import custom styles
import '../styles/Swiper-Customs.css';

// Import teacher images from assets
import teacher1 from '../assets/teachers/坂口先生.jpg';
import teacher2 from '../assets/teachers/樋山先生.jpg';
import teacher3 from '../assets/teachers/梅津先生.jpg';
import teacher4 from '../assets/teachers/櫻岡先生.jpg';
import teacher5 from '../assets/teachers/榎本榎本先生.jpg';
import teacher7 from '../assets/teachers/松永先生.jpg';
import teacher8 from '../assets/teachers/京先生.jpg';
import teacher9 from '../assets/teachers/山崎先生.jpg';
import teacher10 from '../assets/teachers/浅野浅野先生.jpg';
import teacher11 from '../assets/teachers/丸山丸山先生.jpg';
import teacher12 from '../assets/teachers/関川関川先生.jpg';
import teacher13 from '../assets/teachers/池内先生.jpg';
import teacher14 from '../assets/teachers/亀山亀山先生.jpg';
import teacher15 from '../assets/teachers/大瀧大瀧先生.jpg';
import teacher16 from '../assets/teachers/渡邊渡邊先生.jpg';
import teacher17 from '../assets/teachers/中野中野先生.jpg';
import teacher18 from '../assets/teachers/大瀧先生.jpg';

const Team = () => {
    const { t } = useTranslation();
    const [isHeroVisible, setIsHeroVisible] = useState(false);
    const heroRef = useRef(null);

    useEffect(() => {
        setIsHeroVisible(true);
        createHeroAnimatedElements();
        
        const sections = document.querySelectorAll('.about-section');
        
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                }
            });
        }, { threshold: 0.1 });
        
        sections.forEach(section => {
            observer.observe(section);
        });
        
        return () => {
            sections.forEach(section => {
                observer.unobserve(section);
            });
            
            const elements = document.querySelector('.about-hero-elements');
            if (elements) {
                while (elements.firstChild) {
                    elements.removeChild(elements.firstChild);
                }
            }
        };
    }, []);

    const createHeroAnimatedElements = () => {
        const container = document.querySelector('.about-hero-elements');
        if (!container) return;
        
        while (container.firstChild) {
            container.removeChild(container.firstChild);
        }
        
        for (let i = 0; i < 20; i++) {
            const shape = document.createElement('div');
            shape.className = 'about-shape';
            
            const shapes = ['circle', 'triangle', 'square', 'plus'];
            const shapeType = shapes[Math.floor(Math.random() * shapes.length)];
            shape.classList.add(`shape-${shapeType}`);
            
            const x = Math.random() * 100;
            const y = Math.random() * 100;
            const size = Math.random() * 30 + 10;
            const opacity = Math.random() * 0.5 + 0.1;
            const animationDelay = Math.random() * 5;
            const animationDuration = Math.random() * 20 + 10;
            
            shape.style.left = `${x}%`;
            shape.style.top = `${y}%`;
            shape.style.width = `${size}px`;
            shape.style.height = `${size}px`;
            shape.style.opacity = opacity;
            shape.style.animationDelay = `${animationDelay}s`;
            shape.style.animationDuration = `${animationDuration}s`;
            
            container.appendChild(shape);
        }
        
        const icons = ['people', 'school', 'groups', 'emoji_people', 'psychology', 'supervisor_account'];
        for (let i = 0; i < 6; i++) {
            const iconWrapper = document.createElement('div');
            iconWrapper.className = 'about-hero-icon';
            
            const x = 10 + (Math.random() * 80);
            const y = 10 + (Math.random() * 80);
            const delay = Math.random() * 5;
            
            iconWrapper.style.left = `${x}%`;
            iconWrapper.style.top = `${y}%`;
            iconWrapper.style.animationDelay = `${delay}s`;
            
            const icon = document.createElement('span');
            icon.className = 'material-icons';
            icon.textContent = icons[i % icons.length];
            
            iconWrapper.appendChild(icon);
            container.appendChild(iconWrapper);
        }
    };

    // Combined all team members data
    const allTeamMembers = [
        // Teachers
        {
            id: 1,
            name: 'Nakano Sensei',
            nameJapanese: '中野先生',
            furigana: 'なかのせんせい',
            role: 'Web Development Instructor',
            sport: 'Basketball',
            message: {
                japanese: 'プログラミングの楽しさを一緒に学びましょう！',
                english: 'Let\'s learn the joy of programming together!',
                notation: '🚀 Ready to code your future!'
            },
            image: teacher1
        },
        {
            id: 2,
            name: 'Maruyama Sensei',
            nameJapanese: '丸山先生',
            furigana: 'まるやませんせい',
            role: 'Data Science Lead Instructor',
            sport: 'Tennis',
            message: {
                japanese: 'データの力で未来を切り開きましょう！',
                english: 'Let\'s open the future with the power of data!',
                notation: '📊 Data is the new oil!'
            },
            image: teacher2
        },
        {
            id: 3,
            name: 'Kameyama Sensei',
            nameJapanese: '亀山先生',
            furigana: 'かめやませんせい',
            role: 'Cybersecurity Instructor',
            sport: 'Gaming',
            message: {
                japanese: 'セキュリティの世界は奥が深いです。一緒に探求していきましょう！',
                english: 'The world of security is deep. Let\'s explore it together!',
                notation: '🔒 Security first, always!'
            },
            image: teacher3
        },
        {
            id: 4,
            name: 'Kyo Sensei',
            nameJapanese: '京先生',
            furigana: 'きょうせんせい',
            role: 'Mobile Development Instructor',
            sport: 'Soccer',
            message: {
                japanese: 'モバイルアプリで世界を変えよう！',
                english: 'Let\'s change the world with mobile apps!',
                notation: '📱 Mobile-first mindset!'
            },
            image: teacher4
        },
        {
            id: 5,
            name: 'Sakaguchi Sensei',
            nameJapanese: '坂口先生',
            furigana: 'さかぐちせんせい',
            role: 'Cloud Architecture Instructor',
            sport: 'Swimming',
            message: {
                japanese: 'クラウドで無限の可能性を！',
                english: 'Infinite possibilities with cloud!',
                notation: '☁️ Sky is not the limit!'
            },
            image: teacher5
        },
        {
            id: 6,
            name: 'Otaki Sensei',
            nameJapanese: '大瀧先生',
            furigana: 'おおたきせんせい',
            role: 'AI & Machine Learning Instructor',
            sport: 'Baseball',
            message: {
                japanese: 'AIで未来を創造しましょう！',
                english: 'Let\'s create the future with AI!',
                notation: '🤖 AI is the future!'
            },
            image: teacher6
        },
        // Management Team
        {
            id: 7,
            name: 'Santos Sensei',
            nameJapanese: 'サントス先生',
            furigana: 'さんとすせんせい',
            role: 'Principal / Director',
            sport: 'Yoga',
            message: {
                japanese: '皆さんの成長を全力でサポートします！',
                english: 'We will fully support your growth!',
                notation: '🌟 Excellence in education!'
            },
            image: 'https://images.unsplash.com/photo-1494790108755-2616b332c8ff?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80'
        },
        {
            id: 8,
            name: 'Wilson Sensei',
            nameJapanese: 'ウィルソン先生',
            furigana: 'うぃるそんせんせい',
            role: 'Vice Principal',
            sport: 'Running',
            message: {
                japanese: '一緒に頑張りましょう！',
                english: 'Let\'s work hard together!',
                notation: '💪 Teamwork makes the dream work!'
            },
            image: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80'
        },
        {
            id: 9,
            name: 'Mitchell Sensei',
            nameJapanese: 'ミッチェル先生',
            furigana: 'みっちぇるせんせい',
            role: 'Career Services Director',
            sport: 'Volleyball',
            message: {
                japanese: 'あなたの夢を実現しましょう！',
                english: 'Let\'s make your dreams come true!',
                notation: '🎯 Your success is our mission!'
            },
            image: 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80'
        },
        {
            id: 10,
            name: 'Rodriguez Sensei',
            nameJapanese: 'ロドリゲス先生',
            furigana: 'ろどりげすせんせい',
            role: 'Student Support Specialist',
            sport: 'Cycling',
            message: {
                japanese: 'いつでもサポートします！',
                english: 'We\'re always here to support you!',
                notation: '🤝 You\'re never alone!'
            },
            image: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80'
        },
        {
            id: 11,
            name: 'Johnson Sensei',
            nameJapanese: 'ジョンソン先生',
            furigana: 'じょんそんせんせい',
            role: 'Registrar',
            sport: 'Golf',
            message: {
                japanese: '手続きのことは任せてください！',
                english: 'Leave all the paperwork to me!',
                notation: '📋 Smooth sailing ahead!'
            },
            image: 'https://images.unsplash.com/photo-1560250097-0b93528c311a?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80'
        },
        {
            id: 12,
            name: 'Park Sensei',
            nameJapanese: 'パク先生',
            furigana: 'ぱくせんせい',
            role: 'IT Director',
            sport: 'Table Tennis',
            message: {
                japanese: 'テクノロジーで学習をサポート！',
                english: 'Supporting learning with technology!',
                notation: '💻 Tech solutions for everyone!'
            },
            image: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80'
        }
    ];

    // Swiper Slide Component
    const SwiperSlideCard = ({ member }) => (
        <div className="w-full h-full bg-white rounded-3xl shadow-xl overflow-hidden group hover:shadow-2xl transition-all duration-500 transform hover:scale-105 relative">
            {/* Parallax background */}
            <div
                className="absolute inset-0 bg-gradient-to-br from-blue-100 via-purple-100 to-pink-100"
                data-swiper-parallax="-23%"
            ></div>
            
            {/* Hover overlay effect in the middle */}
            <div className="absolute inset-0 bg-gradient-to-br from-blue-600/0 via-purple-600/0 to-pink-600/0 group-hover:from-blue-600/10 group-hover:via-purple-600/10 group-hover:to-pink-600/10 transition-all duration-500 z-5"></div>
            
            {/* Central hover effect */}
            <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-all duration-500 z-10">
                <div className="w-16 h-16 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center border border-white/30">
                    <User className="w-8 h-8 text-white animate-pulse" />
                </div>
            </div>
            
            <div className="relative z-10 p-6 h-full flex flex-col">
                {/* Image with parallax - Resized */}
                <div 
                    className="flex justify-center mb-4"
                    data-swiper-parallax="-100"
                >
                    <div className="w-24 h-24 rounded-full overflow-hidden border-3 border-white shadow-lg group-hover:border-blue-300 transition-colors duration-300">
                        <img
                            src={member.image}
                            alt={member.name}
                            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                            onError={(e) => {
                                e.target.src = 'https://images.unsplash.com/photo-1494790108755-2616b332c8ff?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80';
                            }}
                        />
                    </div>
                </div>
    
                {/* Name Section with parallax - Compressed */}
                <div 
                    className="text-center mb-4"
                    data-swiper-parallax="-200"
                >
                    {/* English Name */}
                    <h3 className="text-lg font-bold text-gray-900 mb-1 group-hover:text-blue-600 transition-colors duration-300">
                        {member.name}
                    </h3>
                    
                    {/* Japanese Name */}
                    <p className="text-base font-semibold text-blue-600 mb-1 group-hover:text-purple-600 transition-colors duration-300">
                        {member.nameJapanese}
                    </p>
                    
                    {/* Furigana */}
                    <p className="text-xs text-gray-500 mb-2">
                        ({member.furigana})
                    </p>
                    
                    {/* Role */}
                    <div className="flex items-center justify-center text-purple-600 text-xs font-medium group-hover:text-blue-600 transition-colors duration-300">
                        <GraduationCap className="w-3 h-3 mr-1" />
                        {member.role}
                    </div>
                </div>
    
                {/* Sport Section with parallax - Compressed */}
                <div 
                    className="text-center mb-4"
                    data-swiper-parallax="-300"
                    data-swiper-parallax-duration="600"
                >
                    <div className="flex items-center justify-center text-green-600 text-xs">
                        <Star className="w-3 h-3 mr-1" />
                        <span className="font-medium">Sport:</span>
                        <span className="ml-1 px-2 py-1 bg-green-100 text-green-700 rounded-full text-xs font-medium group-hover:bg-green-200 transition-colors duration-300">
                            {member.sport}
                        </span>
                    </div>
                </div>
    
                {/* Message Section with different parallax effects - Compressed */}
                <div className="mb-4 flex-grow">
                    {/* Japanese Message with opacity parallax */}
                    <div 
                        className="mb-3 p-3 bg-gradient-to-r from-blue-50 to-purple-50 rounded-lg border-l-3 border-blue-400 group-hover:from-blue-100 group-hover:to-purple-100 transition-colors duration-300"
                        data-swiper-parallax-opacity="0.5"
                    >
                        <h4 className="text-xs font-semibold text-gray-700 mb-1 flex items-center">
                            🇯🇵 Japanese:
                        </h4>
                        <p className="text-xs text-gray-600 leading-relaxed line-clamp-2">
                            {member.message.japanese}
                        </p>
                    </div>
    
                    {/* English Message with scale parallax */}
                    <div 
                        className="mb-3 p-3 bg-gradient-to-r from-green-50 to-blue-50 rounded-lg border-l-3 border-green-400 group-hover:from-green-100 group-hover:to-blue-100 transition-colors duration-300"
                        data-swiper-parallax-scale="0.15"
                    >
                        <h4 className="text-xs font-semibold text-gray-700 mb-1 flex items-center">
                            🇺🇸 English:
                        </h4>
                        <p className="text-xs text-gray-600 leading-relaxed line-clamp-2">
                            {member.message.english}
                        </p>
                    </div>
    
                    {/* Notation with special animation */}
                    <div 
                        className="p-2 bg-gradient-to-r from-yellow-100 to-orange-100 rounded-lg text-center border border-yellow-300 group-hover:from-yellow-200 group-hover:to-orange-200 transition-colors duration-300"
                        data-swiper-parallax="-400"
                    >
                        <p className="text-xs font-bold text-orange-700 group-hover:animate-pulse">
                            {member.message.notation}
                        </p>
                    </div>
                </div>
    
                {/* Contact Info (simplified) - Compressed */}
                <div className="text-center">
                    <div className="flex justify-center space-x-2">
                        <div className="p-2 bg-blue-100 text-blue-600 rounded-full hover:bg-blue-200 transition-colors duration-300 transform hover:scale-110 cursor-pointer group-hover:shadow-md">
                            <Mail className="w-4 h-4" />
                        </div>
                        <div className="p-2 bg-green-100 text-green-600 rounded-full hover:bg-green-200 transition-colors duration-300 transform hover:scale-110 cursor-pointer group-hover:shadow-md">
                            <Phone className="w-4 h-4" />
                        </div>
                        <div className="p-2 bg-purple-100 text-purple-600 rounded-full hover:bg-purple-200 transition-colors duration-300 transform hover:scale-110 cursor-pointer group-hover:shadow-md">
                            <User className="w-4 h-4" />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
    return (
        <div className="about-page">
            {/* Hero Section - Keep existing */}
            <section 
                ref={heroRef}
                className={`min-h-screen bg-gradient-to-br from-blue-50 via-white to-purple-50 flex items-center ${isHeroVisible ? 'visible' : ''}`}
            >
                <div className="about-hero-elements"></div>
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <div className="text-center py-20">
                        <div className="inline-flex items-center bg-blue-100 text-blue-600 px-4 py-2 rounded-full text-sm font-semibold uppercase tracking-wider mb-8">
                            <span className="material-icons mr-2">people</span>
                            {t('Hello, Welcome to Our Faculty') || 'Hello, Welcome to Our Faculty'}
                        </div>
                        
                        <h1 className="text-5xl md:text-6xl lg:text-7xl font-black text-gray-900 leading-tight mb-8">
                            {t('Meet Our Amazing') || 'Meet Our Amazing'} <br />
                            <span className="bg-gradient-to-r from-blue-600 via-purple-600 to-indigo-600 bg-clip-text text-transparent block md:inline">
                                {t('Faculty Team') || 'Faculty Team'}
                            </span>
                        </h1>
                        
                        <p className="text-xl md:text-2xl text-gray-600 leading-relaxed max-w-4xl mx-auto mb-12 font-light">
                            {t('Hello! Welcome to our dedicated team of passionate educators and professionals who are committed to transforming your learning journey. Our faculty brings together industry expertise and academic excellence to provide you with world-class education.') || 'Hello! Welcome to our dedicated team of passionate educators and professionals who are committed to transforming your learning journey. Our faculty brings together industry expertise and academic excellence to provide you with world-class education.'}
                        </p>
                        
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-8 mb-12">
                            <div className="text-center group">
                                <div className="text-4xl md:text-5xl font-bold text-gray-900 mb-2 group-hover:text-blue-600 transition-colors duration-300">
                                    50+
                                </div>
                                <div className="text-sm md:text-base text-gray-600 font-medium uppercase tracking-wide">
                                    {t('Expert Faculty Members') || 'Expert Faculty Members'}
                                </div>
                            </div>
                            <div className="text-center group">
                                <div className="text-4xl md:text-5xl font-bold text-gray-900 mb-2 group-hover:text-purple-600 transition-colors duration-300">
                                    15+
                                </div>
                                <div className="text-sm md:text-base text-gray-600 font-medium uppercase tracking-wide">
                                    {t('Years Combined Experience') || 'Years Combined Experience'}
                                </div>
                            </div>
                            <div className="text-center group">
                                <div className="text-4xl md:text-5xl font-bold text-gray-900 mb-2 group-hover:text-green-600 transition-colors duration-300">
                                    95%
                                </div>
                                <div className="text-sm md:text-base text-gray-600 font-medium uppercase tracking-wide">
                                    {t('Student Satisfaction Rate') || 'Student Satisfaction Rate'}
                                </div>
                            </div>
                            <div className="text-center group">
                                <div className="text-4xl md:text-5xl font-bold text-gray-900 mb-2 group-hover:text-indigo-600 transition-colors duration-300">
                                    100+
                                </div>
                                <div className="text-sm md:text-base text-gray-600 font-medium uppercase tracking-wide">
                                    {t('Professional Certifications') || 'Professional Certifications'}
                                </div>
                            </div>
                        </div>
                        
                        <div className="flex flex-col sm:flex-row gap-4 justify-center items-center">
                            <a 
                                href="#team-members" 
                                className="inline-flex items-center px-8 py-4 bg-gradient-to-r from-blue-600 to-purple-600 text-white font-semibold text-lg rounded-full shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300 hover:from-blue-700 hover:to-purple-700"
                            >
                                <span className="material-icons mr-2">groups</span>
                                {t('Explore Our Faculty') || 'Explore Our Faculty'}
                            </a>
                            <a 
                                href="/contact" 
                                className="inline-flex items-center px-8 py-4 border-2 border-gray-800 text-gray-800 font-semibold text-lg rounded-full hover:bg-gray-800 hover:text-white transition-all duration-300 hover:shadow-lg transform hover:scale-105"
                            >
                                <span className="material-icons mr-2">work</span>
                                {t('Join Our Team') || 'Join Our Team'}
                            </a>
                        </div>
                    </div>
                </div>
            </section>

            {/* Team Section with Swiper */}
            <section id="team-members" className="py-20 bg-gradient-to-br from-gray-50 to-blue-50">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    {/* Section Header */}
                    <div className="text-center mb-16">
                        <h2 className="text-4xl font-bold text-gray-900 mb-4">
                            Our <span className="text-blue-600">Faculty Teams</span>
                        </h2>
                        <p className="text-lg text-gray-600 max-w-3xl mx-auto">
                            Our dedicated team of professionals brings years of industry experience and passion for education to help you succeed in your learning journey.
                        </p>
                    </div>

                    {/* Swiper Container */}
                    <div className="swiper-container">
                        <Swiper
                            speed={600}
                            parallax={true}
                            pagination={{
                                clickable: true,
                                dynamicBullets: true,
                            }}
                            navigation={true}
                            autoplay={{
                                delay: 5000,
                                disableOnInteraction: false,
                            }}
                            modules={[Parallax, Pagination, Navigation, Autoplay]}
                            spaceBetween={20}
                            slidesPerView={1}
                            breakpoints={{
                                640: {
                                    slidesPerView: 2,
                                    spaceBetween: 25,
                                },
                                1024: {
                                    slidesPerView: 3,
                                    spaceBetween: 30,
                                },
                                1280: {
                                    slidesPerView: 4,
                                    spaceBetween: 35,
                                },
                            }}
                            className="team-swiper"
                        >
                            {/* Parallax background element */}
                            <div
                                className="absolute inset-0 bg-gradient-to-br from-blue-200 via-purple-200 to-pink-200 opacity-30"
                                data-swiper-parallax="-23%"
                            ></div>
                            
                            {allTeamMembers.map((member) => (
                                <SwiperSlide key={member.id} className="h-auto">
                                    <div className="h-full min-h-[480px]">
                                        <SwiperSlideCard member={member} />
                                    </div>
                                </SwiperSlide>
                            ))}
                        </Swiper>
                    </div>
                </div>
            </section>
        </div>
    );
};

export default Team;
